INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (964, 185076, 5, 1503, '发泄', '痛苦的根源源于我的工作，我是一名银行的柜员，就是钞票营业员，随着WTO的加入，同业竞争加据，银行业为了与时俱进，花样百出。对行员的要求是以日俱增，一重重的压力压得我快窒息了。考试，上课，任务，这些还不够，还要担心工作风险，一不小心就有经济损失，接下来还要受客户的气，好象我是欠他的一样，有些制度是不能违反，制度又不是我定，我也没办法，又不是故意要为难他，怎能就不解人意。其实尊重是平等的，你尊重为你服务的人，为你服务的人自然就为你服务周到，不尊重劳动者的人，有什么资格要求别人以礼相待。', '痛苦的根源源于我的工作，我是一名银行的柜员，就是钞票营业员，随着WTO的加入，同业竞争加据，银行业为了与时俱进，花样百出。对行员的要求是以日俱增，一重重的压力压得我快窒息了。考试，上课，任务，这些还不够，还要担心工作风险，一不小心就有经济损失，接下来还要受客户的气，好象我是欠他的一样，有些制度是不能违反，制度又不是我定，我也没办法，又不是故意要为难他，怎能就不解人意。其实尊重是平等的，你尊重为你服务的人，为你服务的人自然就为你服务周到，不尊重劳动者的人，有什么资格要求别人以礼相待。', NULL, '2002-10-03 11:27:00', 3, '20021105184525_bbsid_185076_board_5_a3333cadb9.html', '20021105184525');
